/**
 * Cooee SDK for Anveshan
 * Smart conversion optimization — tracks behavior, calculates intent, shows the right engagement at the right time
 * Version: 3.1.0 — Now with browser fingerprinting for reliable unique visitor identification
 */
(function (window, document) {
  "use strict";

  const COOEE_VERSION = "3.1.0";

  // ─── Configuration ───
  const config = {
    appId: null,
    apiBase: "",  // Will be set to the Cooee dashboard URL
    trackingEnabled: true,
    debugMode: false,
    syncInterval: 10000,  // Sync with server every 10s
    engageCheckInterval: 15000, // Check for engagements every 15s
  };

  // ─── Visitor Data ───
  const visitor = {
    id: null,           // Will be set to fingerprint hash
    fingerprintId: null, // Raw FingerprintJS visitorId
    confidence: 0,       // FingerprintJS confidence score (0-1)
    sessionId: null,
    isReturning: false,  // true if we've seen this fingerprint before
    visitCount: 0,       // total number of visits
    firstSeenAt: null,   // timestamp of very first visit
    intent: "low",
    intentScore: 0,
    pageViews: 0,
    timeOnSite: 0,
    scrollDepth: 0,
    clickCount: 0,
    cartItems: 0,
    cartValue: 0,
    source: "direct",
    device: /Mobi|Android/i.test(navigator.userAgent) ? "mobile" : "desktop",
    entryPage: window.location.pathname,
    currentPage: window.location.pathname,
    pages: [window.location.pathname],
    converted: false,
    email: null,
    phone: null,
    isLoggedIn: false,
    shopifyCustomer: null,  // Will be populated if Shopify customer detected
    idle: false,
    idleTime: 0,
  };

  // ─── State ───
  const state = {
    initialized: false,
    fingerprintReady: false,
    syncing: false,
    engagementsShown: [],
    exitIntentFired: false,
    cartCheckDone: false,
    syncTimer: null,
    engageTimer: null,
    idleTimer: null,
    pendingEvents: [], // Queue events until fingerprint is ready
  };

  // ─── Utilities ───
  function generateId() {
    return "cooee_" + Math.random().toString(36).substr(2, 9) + Date.now().toString(36);
  }

  function log() {
    if (config.debugMode) {
      console.log.apply(console, ["[Cooee]"].concat(Array.prototype.slice.call(arguments)));
    }
  }

  function detectSource() {
    var ref = document.referrer;
    if (!ref) return "direct";
    if (ref.includes("google")) return "google_organic";
    if (ref.includes("facebook") || ref.includes("fb.com")) return "meta_ads";
    if (ref.includes("instagram")) return "instagram";
    if (ref.includes("whatsapp") || ref.includes("wa.me")) return "whatsapp";
    if (ref.includes("youtube")) return "youtube";
    if (ref.includes("twitter") || ref.includes("x.com")) return "twitter";
    var params = new URLSearchParams(window.location.search);
    if (params.get("utm_source")) return params.get("utm_source");
    if (params.get("gclid")) return "google_ads";
    if (params.get("fbclid")) return "meta_ads";
    return ref.replace(/https?:\/\/(www\.)?/, "").split("/")[0];
  }

  // ─── Browser Fingerprinting ───
  // Uses canvas, WebGL, audio, fonts, screen, timezone, etc. to create a stable hash
  // Same browser + same device = same fingerprint, even without cookies

  function loadFingerprintJS() {
    return new Promise(function (resolve) {
      // Check if already loaded globally
      if (window.FingerprintJS) {
        resolve(window.FingerprintJS);
        return;
      }

      // FingerprintJS v4 open-source — use the IIFE (non-module) build
      var script = document.createElement("script");
      script.src = "https://openfpcdn.io/fingerprintjs/v4/iife.min.js";
      script.async = true;
      script.onload = function () {
        // v4 IIFE build sets window.FingerprintJS
        if (window.FingerprintJS) {
          log("✅ FingerprintJS v4 loaded from CDN");
          resolve(window.FingerprintJS);
        } else {
          log("⚠️ FingerprintJS script loaded but global not found");
          resolve(null);
        }
      };
      script.onerror = function () {
        log("⚠️ FingerprintJS CDN blocked or unreachable (adblocker?)");
        resolve(null);
      };
      document.head.appendChild(script);
    });
  }

  async function getFingerprint() {
    try {
      var FP = await loadFingerprintJS();

      if (FP) {
        var fp = await FP.load();
        var result = await fp.get();

        visitor.fingerprintId = result.visitorId;
        visitor.confidence = result.confidence.score;

        log("🔑 Fingerprint:", result.visitorId);
        log("🎯 Confidence:", (result.confidence.score * 100).toFixed(1) + "%");
        log("📋 Components used:", Object.keys(result.components).length);

        return result.visitorId;
      }
    } catch (e) {
      log("Fingerprint error:", e.message);
    }

    // Fallback: only if FingerprintJS completely fails (adblocker, no internet, etc.)
    log("⚠️ Using canvas fallback — FingerprintJS unavailable");
    return buildFallbackFingerprint();
  }

  // Fallback fingerprint if FingerprintJS fails to load (adblocker, CDN down, etc.)
  function buildFallbackFingerprint() {
    var signals = [
      navigator.userAgent,
      navigator.language,
      screen.width + "x" + screen.height,
      screen.colorDepth,
      new Date().getTimezoneOffset(),
      navigator.hardwareConcurrency || "?",
      navigator.deviceMemory || "?",
      navigator.platform,
      // Canvas fingerprint
      getCanvasFingerprint(),
    ].join("|");

    // Simple hash
    var hash = 0;
    for (var i = 0; i < signals.length; i++) {
      var chr = signals.charCodeAt(i);
      hash = ((hash << 5) - hash) + chr;
      hash |= 0;
    }
    var fallbackId = "cooee_fb_" + Math.abs(hash).toString(36);

    visitor.fingerprintId = fallbackId;
    visitor.confidence = 0.6; // Lower confidence for fallback
    log("🔑 Fallback fingerprint:", fallbackId, "(canvas-based)");

    return fallbackId;
  }

  function getCanvasFingerprint() {
    try {
      var canvas = document.createElement("canvas");
      canvas.width = 200;
      canvas.height = 50;
      var ctx = canvas.getContext("2d");
      ctx.textBaseline = "top";
      ctx.font = "14px Arial";
      ctx.fillStyle = "#f60";
      ctx.fillRect(40, 0, 62, 20);
      ctx.fillStyle = "#069";
      ctx.fillText("Cooee🌿", 2, 15);
      ctx.fillStyle = "rgba(102,0,255,0.7)";
      ctx.fillText("Cooee🌿", 4, 17);
      return canvas.toDataURL().slice(-50);
    } catch (e) {
      return "no-canvas";
    }
  }

  // ─── Initialize Visitor (with fingerprint) ───
  async function initVisitor() {
    // Step 1: Get fingerprint (the real unique ID)
    var fingerprintId = await getFingerprint();

    // Step 2: Check localStorage for history of THIS fingerprint
    var stored = null;
    try { stored = JSON.parse(localStorage.getItem("cooee_fp_" + fingerprintId)); } catch (e) { /* ignore */ }

    if (stored) {
      // RETURNING VISITOR — we've seen this exact browser before
      visitor.id = stored.id;
      visitor.isReturning = true;
      visitor.visitCount = (stored.visitCount || 0) + 1;
      visitor.firstSeenAt = stored.firstSeenAt;
      visitor.pageViews = stored.pageViews || 0;
      visitor.pages = stored.pages || [];
      visitor.email = stored.email || null;
      visitor.converted = stored.converted || false;
      log("👋 Returning visitor! Visit #" + visitor.visitCount, "First seen:", new Date(visitor.firstSeenAt).toLocaleDateString());
    } else {
      // Check if there's an OLD cooee_visitor record (migration from v3.0)
      var oldStored = null;
      try { oldStored = JSON.parse(localStorage.getItem("cooee_visitor")); } catch (e) { /* ignore */ }

      if (oldStored && oldStored.id) {
        // Migrate old visitor to fingerprint-based ID
        visitor.id = oldStored.id;
        visitor.isReturning = true;
        visitor.visitCount = (oldStored.pageViews || 1);
        visitor.firstSeenAt = Date.now() - 86400000; // Assume they visited before
        visitor.pages = oldStored.pages || [];
        log("📦 Migrated from v3.0 ID:", visitor.id, "→ fingerprint:", fingerprintId);
      } else {
        // BRAND NEW VISITOR — never seen before
        visitor.id = "cooee_" + fingerprintId;
        visitor.isReturning = false;
        visitor.visitCount = 1;
        visitor.firstSeenAt = Date.now();
        log("🆕 New unique visitor:", visitor.id);
      }
    }

    visitor.sessionId = generateId();
    visitor.pageViews++;
    visitor.source = detectSource();
    visitor.currentPage = window.location.pathname;

    if (!visitor.pages.includes(window.location.pathname)) {
      visitor.pages.push(window.location.pathname);
    }

    saveLocal();

    // Mark fingerprint as ready — flush any pending events
    state.fingerprintReady = true;
    if (state.pendingEvents.length > 0) {
      log("Flushing", state.pendingEvents.length, "pending events");
      state.pendingEvents.forEach(function (pe) {
        sendEvent(pe.event, pe.data);
      });
      state.pendingEvents = [];
    }

    log("Visitor initialized:", visitor.id, "| Returning:", visitor.isReturning, "| Source:", visitor.source, "| Device:", visitor.device);
  }

  function saveLocal() {
    try {
      // Store keyed by fingerprint — survives cookie clears, works across sessions
      var key = visitor.fingerprintId ? "cooee_fp_" + visitor.fingerprintId : "cooee_visitor";
      localStorage.setItem(key, JSON.stringify({
        id: visitor.id,
        fingerprintId: visitor.fingerprintId,
        pageViews: visitor.pageViews,
        pages: visitor.pages,
        visitCount: visitor.visitCount,
        firstSeenAt: visitor.firstSeenAt,
        email: visitor.email,
        converted: visitor.converted,
      }));
    } catch (e) { /* localStorage full or blocked */ }
  }

  // ─── Intent Calculation ───
  function calculateIntent() {
    var score = 0;

    // Time on site (max 25 points) — 1 point per 12 seconds
    score += Math.min(visitor.timeOnSite / 12, 25);

    // Page views (max 20 points) — 5 per page
    score += Math.min(visitor.pageViews * 5, 20);

    // Scroll depth (max 15 points)
    score += (visitor.scrollDepth / 100) * 15;

    // Click engagement (max 15 points) — 2 per click
    score += Math.min(visitor.clickCount * 2, 15);

    // Cart signals (max 25 points)
    if (visitor.cartItems > 0) score += 15;
    if (visitor.cartValue > 500) score += 10;

    // Determine intent level
    var prevIntent = visitor.intent;
    visitor.intentScore = Math.round(score);
    if (score >= 60) visitor.intent = "high";
    else if (score >= 30) visitor.intent = "medium";
    else visitor.intent = "low";

    if (visitor.intent !== prevIntent) {
      log("Intent changed:", prevIntent, "→", visitor.intent, "(score: " + visitor.intentScore + ")");
      sendEvent("intent_changed", { from: prevIntent, to: visitor.intent, score: visitor.intentScore });

      // Trigger engagement check on intent change
      checkEngagements("intent_change");
    }
  }

  // ─── Tracking (all listeners are passive + debounced to minimize TBT) ───
  function trackScroll() {
    var maxScroll = 0;
    var scrollTimer = null;
    window.addEventListener("scroll", function () {
      // Debounce: only calculate every 200ms, not every scroll pixel
      if (scrollTimer) return;
      scrollTimer = setTimeout(function () {
        scrollTimer = null;
        var h = document.documentElement.scrollHeight - window.innerHeight;
        if (h <= 0) return;
        var pct = Math.round((window.scrollY / h) * 100);
        if (pct > maxScroll) {
          maxScroll = pct;
          visitor.scrollDepth = maxScroll;
          calculateIntent();
        }
      }, 200);
    }, { passive: true });  // passive = browser doesn't wait for JS before scrolling
  }

  function trackClicks() {
    document.addEventListener("click", function (e) {
      visitor.clickCount++;
      calculateIntent();

      // Track specific click targets for analytics
      var target = e.target;
      if (target.tagName === "A" || target.closest("a")) {
        var link = target.tagName === "A" ? target : target.closest("a");
        sendEvent("link_click", { href: link.href, text: (link.textContent || "").trim().substring(0, 50) });
      }
      if (target.tagName === "BUTTON" || target.closest("button")) {
        var btn = target.tagName === "BUTTON" ? target : target.closest("button");
        sendEvent("button_click", { text: (btn.textContent || "").trim().substring(0, 50) });
      }
    });
  }

  function trackTime() {
    setInterval(function () {
      if (!visitor.idle) {
        visitor.timeOnSite += 5;
        calculateIntent();
      }
    }, 5000);
  }

  // ─── Idle Detection ───
  function trackIdle() {
    var idleTimeout = null;
    var resetIdle = function () {
      visitor.idle = false;
      visitor.idleTime = 0;
      clearTimeout(idleTimeout);
      idleTimeout = setTimeout(function () {
        visitor.idle = true;
        log("Visitor idle");
        // If on cart/checkout and idle = potential abandonment
        if (visitor.currentPage.includes("/cart") || visitor.currentPage.includes("/checkout")) {
          checkEngagements("cart_idle");
        }
      }, 30000); // 30s of no activity = idle
    };

    ["mousemove", "keydown", "scroll", "touchstart", "click"].forEach(function (evt) {
      document.addEventListener(evt, resetIdle, { passive: true });
    });

    resetIdle();
  }

  // ─── Shopify Cart Auto-Detection ───
  function detectShopifyCart() {
    // Method 1: Fetch /cart.js (works on all Shopify stores)
    function fetchCart() {
      fetch("/cart.js", { credentials: "same-origin" })
        .then(function (r) { return r.json(); })
        .then(function (cart) {
          if (cart && typeof cart.item_count === "number") {
            var prevItems = visitor.cartItems;
            visitor.cartItems = cart.item_count;
            visitor.cartValue = (cart.total_price || 0) / 100; // Shopify stores in paise/cents
            calculateIntent();

            if (cart.item_count > prevItems) {
              sendEvent("cart_updated", {
                items: cart.item_count,
                value: visitor.cartValue,
                currency: cart.currency,
              });
              log("Cart updated:", cart.item_count, "items, ₹" + visitor.cartValue);
            }
          }
        })
        .catch(function () {
          // Not a Shopify store or cart not available
        });
    }

    // Check cart on load
    fetchCart();

    // Method 2: Intercept Shopify AJAX cart calls
    var origFetch = window.fetch;
    window.fetch = function () {
      var url = arguments[0];
      if (typeof url === "string" && (url.includes("/cart/add") || url.includes("/cart/change") || url.includes("/cart/update"))) {
        // Cart was modified, re-fetch after a short delay
        var result = origFetch.apply(this, arguments);
        result.then(function () {
          setTimeout(fetchCart, 500);
        });
        return result;
      }
      return origFetch.apply(this, arguments);
    };

    // Method 3: Listen for XMLHttpRequest cart calls
    var origOpen = XMLHttpRequest.prototype.open;
    XMLHttpRequest.prototype.open = function () {
      var url = arguments[1];
      if (typeof url === "string" && (url.includes("/cart/add") || url.includes("/cart/change"))) {
        this.addEventListener("load", function () {
          setTimeout(fetchCart, 500);
        });
      }
      return origOpen.apply(this, arguments);
    };

    state.cartCheckDone = true;
  }

  // ─── Shopify Customer Identity Detection ───
  // Merges fingerprint (anonymous) with Shopify customer (known identity)
  // This prevents loyal customers from getting "new visitor" offers on a different device

  function detectShopifyCustomer() {
    var customer = {
      id: null,
      email: null,
      name: null,
      phone: null,
      ordersCount: 0,
      totalSpent: 0,
      tags: [],
      isLoggedIn: false,
      tier: "new",  // "new", "returning", "loyal", "vip"
    };

    // ── Method 1: ShopifyAnalytics.meta (available on all Shopify pages) ──
    try {
      if (window.ShopifyAnalytics && window.ShopifyAnalytics.meta && window.ShopifyAnalytics.meta.page) {
        var meta = window.ShopifyAnalytics.meta.page;
        if (meta.customerId) {
          customer.id = String(meta.customerId);
          customer.isLoggedIn = true;
          log("🛍️ Shopify customer ID found via analytics:", customer.id);
        }
      }
    } catch (e) { /* ignore */ }

    // ── Method 2: Read __st_logged_in cookie (Shopify sets this) ──
    try {
      var cookies = document.cookie.split(";");
      for (var i = 0; i < cookies.length; i++) {
        var c = cookies[i].trim();
        if (c.startsWith("_shopify_s=") || c.startsWith("_s=")) {
          // Shopify session exists = likely logged in
        }
        if (c.startsWith("cart_currency=")) {
          // Confirms it's a Shopify store
        }
      }
    } catch (e) { /* ignore */ }

    // ── Method 3: Read meta.customer from Liquid-rendered data ──
    // Many Shopify themes render this in theme.liquid:
    //   <script>window.__customer = {{ customer | json }};</script>
    // Or in the global __st object
    try {
      // Check for common Shopify customer globals
      var sources = [
        window.__customer,
        window.__st && window.__st.cid ? { id: window.__st.cid } : null,
        window.theme && window.theme.customer,
        window.meta && window.meta.customer,
      ];

      for (var s = 0; s < sources.length; s++) {
        var src = sources[s];
        if (src && (src.id || src.email)) {
          customer.id = String(src.id || "");
          customer.email = src.email || null;
          customer.name = src.name || src.first_name || null;
          customer.phone = src.phone || src.default_address?.phone || null;
          customer.ordersCount = src.orders_count || 0;
          customer.totalSpent = parseFloat(src.total_spent || 0);
          customer.tags = src.tags || [];
          customer.isLoggedIn = true;
          log("🛍️ Shopify customer data found:", customer.name, "| Orders:", customer.ordersCount);
          break;
        }
      }
    } catch (e) { /* ignore */ }

    // ── Method 4: Fetch /account.json (if logged in) ──
    if (!customer.isLoggedIn) {
      fetch("/account", { credentials: "same-origin", redirect: "manual" })
        .then(function (r) {
          // If redirects to /account/login → not logged in
          // If 200 → logged in
          if (r.status === 200 && !r.redirected) {
            customer.isLoggedIn = true;
            log("🛍️ Customer is logged in (detected via /account)");
            // We know they're logged in but don't have details
            // The engagement engine will check server-side
          }
        })
        .catch(function () { /* not shopify or account inaccessible */ });
    }

    // ── Calculate customer tier ──
    if (customer.ordersCount >= 10 || customer.totalSpent >= 5000) {
      customer.tier = "vip";
    } else if (customer.ordersCount >= 3) {
      customer.tier = "loyal";
    } else if (customer.ordersCount >= 1) {
      customer.tier = "returning";
    } else {
      customer.tier = "new";
    }

    // ── Check if different Shopify user on same device (shared device) ──
    var lastCustomerId = null;
    try { lastCustomerId = localStorage.getItem("cooee_last_customer_id"); } catch (e) { /* ignore */ }

    if (customer.isLoggedIn && customer.id && lastCustomerId && lastCustomerId !== customer.id) {
      // Different person logged in on same device — reset engagement state
      log("⚠️ Different Shopify customer on same device! Was:", lastCustomerId, "Now:", customer.id);
      visitor.engagementsShown = [];
      state.engagementsShown = [];
      state.exitIntentFired = false;
    }

    if (customer.isLoggedIn && customer.id) {
      try { localStorage.setItem("cooee_last_customer_id", customer.id); } catch (e) { /* ignore */ }
    }

    // ── Merge with visitor ──
    visitor.shopifyCustomer = customer;

    if (customer.isLoggedIn) {
      visitor.isLoggedIn = true;
      if (customer.email) visitor.email = customer.email;
      if (customer.phone) visitor.phone = customer.phone;

      // CRITICAL: If this is a known customer with orders,
      // override the "isReturning" flag — this is NOT a new visitor
      // even if the fingerprint is new (different device)
      if (customer.ordersCount > 0) {
        visitor.isReturning = true;
        visitor.visitCount = Math.max(visitor.visitCount, customer.ordersCount);
      }

      sendEvent("customer_identified", {
        shopifyCustomerId: customer.id,
        ordersCount: customer.ordersCount,
        totalSpent: customer.totalSpent,
        tier: customer.tier,
        fingerprintId: visitor.fingerprintId,
      });

      log("👤 Customer tier:", customer.tier,
        "| Orders:", customer.ordersCount,
        "| Spent: ₹" + customer.totalSpent,
        "| Fingerprint linked:", visitor.fingerprintId);
    } else {
      log("👤 Visitor not logged in — using fingerprint identity only");
    }

    return customer;
  }

  // ─── Exit Intent (Desktop + Mobile) ───
  function detectExitIntent(callback) {
    // Desktop: mouse leaves viewport
    if (visitor.device === "desktop") {
      document.addEventListener("mouseout", function (e) {
        if (e.clientY <= 0 && !state.exitIntentFired) {
          state.exitIntentFired = true;
          log("Exit intent detected (desktop)");
          sendEvent("exit_intent", { method: "mouseout" });
          callback();
        }
      });
    }

    // Mobile: back button / visibility change
    document.addEventListener("visibilitychange", function () {
      if (document.visibilityState === "hidden" && !state.exitIntentFired) {
        state.exitIntentFired = true;
        log("Exit intent detected (visibility change)");
        sendEvent("exit_intent", { method: "visibility_change" });
        // Can't show popup when page is hidden, so queue it for when they come back
        document.addEventListener("visibilitychange", function onReturn() {
          if (document.visibilityState === "visible") {
            document.removeEventListener("visibilitychange", onReturn);
            callback();
          }
        });
      }
    });

    // Mobile: browser back button via popstate
    if (visitor.device === "mobile") {
      // Push a dummy state so we can detect back
      history.pushState({ cooee: true }, "");
      window.addEventListener("popstate", function (e) {
        if (!state.exitIntentFired) {
          state.exitIntentFired = true;
          log("Exit intent detected (back button)");
          sendEvent("exit_intent", { method: "back_button" });
          callback();
        }
      });
    }
  }

  // ─── Server Communication ───
  function sendEvent(event, data) {
    if (!config.apiBase || !config.trackingEnabled) return;

    // If fingerprint isn't ready yet, queue the event
    if (!state.fingerprintReady) {
      state.pendingEvents.push({ event: event, data: data });
      log("Event queued (waiting for fingerprint):", event);
      return;
    }

    var payload = {
      visitorId: visitor.id,
      sessionId: visitor.sessionId,
      event: event,
      data: data || {},
      page: window.location.pathname,
      visitor: {
        intent: visitor.intent,
        intentScore: visitor.intentScore,
        pageViews: visitor.pageViews,
        timeOnSite: visitor.timeOnSite,
        scrollDepth: visitor.scrollDepth,
        clickCount: visitor.clickCount,
        cartItems: visitor.cartItems,
        cartValue: visitor.cartValue,
        source: visitor.source,
        device: visitor.device,
        entryPage: visitor.entryPage,
        currentPage: visitor.currentPage,
        pages: visitor.pages,
        converted: visitor.converted,
        email: visitor.email,
        // Fingerprint data
        fingerprintId: visitor.fingerprintId,
        confidence: visitor.confidence,
        isReturning: visitor.isReturning,
        visitCount: visitor.visitCount,
        firstSeenAt: visitor.firstSeenAt,
      },
    };

    fetch(config.apiBase + "/api/events", {
      method: "POST",
      headers: { "Content-Type": "application/json", "X-App-Id": config.appId || "" },
      body: JSON.stringify(payload),
    }).catch(function (e) {
      log("Event send failed:", e.message);
    });
  }

  // Periodic sync — keeps dashboard updated
  function startSync() {
    config.syncTimer = setInterval(function () {
      sendEvent("heartbeat", {
        intentScore: visitor.intentScore,
        timeOnSite: visitor.timeOnSite,
        scrollDepth: visitor.scrollDepth,
      });
    }, config.syncInterval);
  }

  // ─── Engagement Engine ───
  function checkEngagements(trigger) {
    if (!config.apiBase) return;

    fetch(config.apiBase + "/api/engage", {
      method: "POST",
      headers: { "Content-Type": "application/json", "X-App-Id": config.appId || "" },
      body: JSON.stringify({
        visitorId: visitor.id,
        page: window.location.pathname,
        trigger: trigger || "page_load",
      }),
    })
      .then(function (r) { return r.json(); })
      .then(function (result) {
        if (result.engagement) {
          showEngagement(result.engagement);
        }
      })
      .catch(function (e) {
        log("Engage check failed:", e.message);
      });
  }

  function showEngagement(engagement) {
    if (state.engagementsShown.includes(engagement.id)) return;
    state.engagementsShown.push(engagement.id);

    var c = engagement.config || {};
    log("Showing engagement:", engagement.name, "(" + engagement.type + ")");

    switch (engagement.type) {
      case "Exit Popup":
      case "Cart Popup":
        createPopup({
          title: c.title || "Wait! Don't leave yet!",
          subtitle: c.subtitle || "Get 20% off on your first order",
          buttonText: c.buttonText || "Claim Discount",
          capture: c.capture || "auto",
          engagementId: engagement.id,
        });
        break;

      case "Announcement Bar":
      case "Trust Bar":
        createAnnouncementBar({
          text: c.text || "Free shipping on orders above ₹499!",
          engagementId: engagement.id,
        });
        break;

      case "Social Proof":
        showSocialProof({
          engagementId: engagement.id,
        });
        break;

      case "Product Bundle":
        createPopup({
          title: c.title || "Better Together!",
          subtitle: c.subtitle || "Bundle and save ₹100",
          buttonText: c.buttonText || "Add Bundle to Cart",
          type: "bundle",
          capture: c.capture || "auto",
          engagementId: engagement.id,
        });
        break;

      case "WhatsApp Capture":
        createPopup({
          title: c.title || "Get 10% Off on WhatsApp!",
          subtitle: c.subtitle || "Enter your number for instant discount",
          buttonText: c.buttonText || "Send My Discount",
          buttonColor: "#25D366",
          type: "whatsapp",
          capture: "phone",
          engagementId: engagement.id,
        });
        break;

      case "Returning Visitor":
        createPopup({
          title: c.title || "Welcome back! 👋",
          subtitle: c.subtitle || "We saved a special discount for you",
          buttonText: c.buttonText || "Claim My Discount",
          type: "returning",
          capture: c.capture || "phone",
          engagementId: engagement.id,
        });
        break;

      case "Quiz":
        createQuiz({
          engagementId: engagement.id,
          config: c,
        });
        break;

      default:
        log("Unknown engagement type:", engagement.type);
    }

    sendEvent("engagement_shown", { engagementId: engagement.id, type: engagement.type });
  }

  // ─── Quiz Engagement (highest phone capture rate) ───

  function createQuiz(options) {
    var opts = options || {};
    var config = opts.config || {};
    if (document.getElementById("cooee-popup-overlay")) return;

    var questions = config.questions || [
      {
        q: "What's your main health goal?",
        options: ["Immunity Boost", "Better Digestion", "Skin & Hair", "Daily Cooking"],
        emoji: "🎯",
      },
      {
        q: "How do you prefer your spices?",
        options: ["Raw / Whole", "Ground Powder", "Ready Mixes", "Not Sure Yet"],
        emoji: "🌿",
      },
      {
        q: "How often do you cook at home?",
        options: ["Daily", "3-4 times a week", "Weekends only", "Rarely"],
        emoji: "🍳",
      },
    ];

    var results = config.results || {
      "Immunity Boost": { product: "Organic Lakadong Turmeric", reason: "7-12% curcumin — highest in India. One spoon in warm milk daily." },
      "Better Digestion": { product: "Cold Pressed Mustard Oil + Panchphoran", reason: "Traditional Bengali combo — improves gut health naturally." },
      "Skin & Hair": { product: "A2 Desi Ghee + Wild Forest Honey", reason: "Applied or consumed — both work. Farm-fresh, no preservatives." },
      "Daily Cooking": { product: "Spices Combo Pack", reason: "Everything you need for Indian cooking — turmeric, mustard oil, ghee, honey." },
    };

    var currentQ = 0;
    var answers = [];

    var overlay = document.createElement("div");
    overlay.id = "cooee-popup-overlay";
    overlay.style.cssText = "position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);z-index:99999;display:flex;align-items:center;justify-content:center;animation:cooee-fadeIn 0.3s ease";

    var popup = document.createElement("div");
    popup.style.cssText = "background:#ffffff;border-radius:16px;max-width:440px;width:92%;box-shadow:0 25px 50px rgba(0,0,0,0.25);overflow:hidden;animation:cooee-slideUp 0.3s ease;position:relative;font-family:-apple-system,BlinkMacSystemFont,sans-serif";

    function renderQuestion() {
      var q = questions[currentQ];
      var progress = ((currentQ + 1) / (questions.length + 1)) * 100;

      popup.innerHTML =
        '<div style="background:linear-gradient(135deg,#6366f1,#8b5cf6);padding:20px 24px;color:white">' +
          '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">' +
            '<span style="font-size:13px;opacity:0.8">Question ' + (currentQ + 1) + ' of ' + questions.length + '</span>' +
            '<span style="font-size:24px">' + q.emoji + '</span>' +
          '</div>' +
          '<div style="background:rgba(255,255,255,0.2);border-radius:99px;height:4px;margin-bottom:16px">' +
            '<div style="background:white;border-radius:99px;height:4px;width:' + progress + '%;transition:width 0.3s"></div>' +
          '</div>' +
          '<h2 style="font-size:18px;font-weight:700;margin:0">' + q.q + '</h2>' +
        '</div>' +
        '<div style="padding:20px 24px">' +
          q.options.map(function (opt, i) {
            return '<button class="cooee-quiz-opt" data-idx="' + i + '" style="width:100%;padding:12px 16px;margin-bottom:8px;border:2px solid #e2e8f0;border-radius:10px;background:white;font-size:14px;font-weight:500;cursor:pointer;text-align:left;transition:all 0.15s;color:#334155" onmouseover="this.style.borderColor=\'#6366f1\';this.style.background=\'#f5f3ff\'" onmouseout="this.style.borderColor=\'#e2e8f0\';this.style.background=\'white\'">' + opt + '</button>';
          }).join("") +
          '<p style="font-size:11px;color:#94a3b8;text-align:center;margin:8px 0 0">🔒 No sign-up needed</p>' +
        '</div>';

      // Add close button
      var close = document.createElement("button");
      close.innerHTML = "✕";
      close.style.cssText = "position:absolute;top:12px;right:12px;width:28px;height:28px;border-radius:50%;border:none;background:rgba(255,255,255,0.3);cursor:pointer;font-size:14px;display:flex;align-items:center;justify-content:center;z-index:1;color:white";
      close.onclick = function () {
        overlay.style.animation = "cooee-fadeOut 0.3s ease";
        setTimeout(function () { overlay.remove(); }, 300);
        sendEvent("engagement_dismissed", { engagementId: opts.engagementId, step: "q" + (currentQ + 1) });
      };
      popup.appendChild(close);

      // Bind option clicks
      var btns = popup.querySelectorAll(".cooee-quiz-opt");
      btns.forEach(function (b) {
        b.onclick = function () {
          answers.push(b.textContent);
          sendEvent("quiz_answer", { question: currentQ + 1, answer: b.textContent, engagementId: opts.engagementId });

          if (currentQ < questions.length - 1) {
            currentQ++;
            popup.style.animation = "cooee-fadeIn 0.2s ease";
            renderQuestion();
          } else {
            renderCapture();
          }
        };
      });
    }

    function renderCapture() {
      var firstAnswer = answers[0] || "Daily Cooking";
      var result = results[firstAnswer] || results["Daily Cooking"];

      popup.innerHTML =
        '<div style="background:linear-gradient(135deg,#22c55e,#16a34a);padding:20px 24px;color:white">' +
          '<div style="background:rgba(255,255,255,0.2);border-radius:99px;height:4px;margin-bottom:16px">' +
            '<div style="background:white;border-radius:99px;height:4px;width:100%"></div>' +
          '</div>' +
          '<h2 style="font-size:18px;font-weight:700;margin:0">Your perfect match is ready! ✨</h2>' +
          '<p style="font-size:13px;opacity:0.9;margin:6px 0 0">Based on your answers, we recommend:</p>' +
        '</div>' +
        '<div style="padding:20px 24px">' +
          '<div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:10px;padding:14px;margin-bottom:16px">' +
            '<p style="font-size:15px;font-weight:700;color:#166534;margin:0">' + result.product + '</p>' +
            '<p style="font-size:12px;color:#4aba7a;margin:6px 0 0;line-height:1.4">' + result.reason + '</p>' +
          '</div>' +
          '<p style="font-size:13px;color:#475569;font-weight:600;margin:0 0 10px;text-align:center">Get your personalized recommendation + exclusive recipe on WhatsApp</p>' +
          '<div style="display:flex;gap:8px;margin-bottom:10px">' +
            '<div style="display:flex;align-items:center;gap:4px;padding:10px 12px;border:1px solid #e2e8f0;border-radius:8px;background:#f8fafc;flex-shrink:0">' +
              '<span style="font-size:16px">🇮🇳</span><span style="font-size:13px;color:#64748b">+91</span>' +
            '</div>' +
            '<input type="tel" id="cooee-quiz-phone" placeholder="WhatsApp number" maxlength="10" inputmode="numeric" style="flex:1;padding:10px 16px;border:1px solid #e2e8f0;border-radius:8px;font-size:14px;box-sizing:border-box;outline:none">' +
          '</div>' +
          '<button id="cooee-quiz-btn" style="width:100%;padding:12px;background:#25D366;color:white;border:none;border-radius:8px;font-size:14px;font-weight:600;cursor:pointer">Send My Recommendation 💬</button>' +
          '<label style="display:flex;align-items:start;gap:6px;margin-top:10px;cursor:pointer">' +
            '<input type="checkbox" id="cooee-quiz-consent" checked style="margin-top:2px;accent-color:#25D366;flex-shrink:0">' +
            '<span style="font-size:11px;color:#64748b;line-height:1.4">I agree to receive my results & offers on WhatsApp</span>' +
          '</label>' +
        '</div>';

      // Close button
      var close = document.createElement("button");
      close.innerHTML = "✕";
      close.style.cssText = "position:absolute;top:12px;right:12px;width:28px;height:28px;border-radius:50%;border:none;background:rgba(255,255,255,0.3);cursor:pointer;font-size:14px;display:flex;align-items:center;justify-content:center;z-index:1;color:white";
      close.onclick = function () {
        overlay.style.animation = "cooee-fadeOut 0.3s ease";
        setTimeout(function () { overlay.remove(); }, 300);
      };
      popup.appendChild(close);

      // Submit handler
      var btn = document.getElementById("cooee-quiz-btn");
      var phoneInput = document.getElementById("cooee-quiz-phone");

      btn.onclick = function () {
        var phone = phoneInput.value.trim().replace(/\D/g, "");
        if (phone.length !== 10 || !/^[6-9]/.test(phone)) {
          phoneInput.style.borderColor = "#ef4444";
          phoneInput.placeholder = "Enter valid 10 digit mobile";
          return;
        }

        var consent = document.getElementById("cooee-quiz-consent");
        var waConsent = consent ? consent.checked : false;

        visitor.phone = "+91" + phone;
        visitor.converted = true;
        saveLocal();

        sendEvent("engagement_clicked", { engagementId: opts.engagementId, phone: "+91" + phone });
        sendEvent("engagement_converted", { engagementId: opts.engagementId });
        sendEvent("contact_captured", {
          phone: "+91" + phone,
          waConsent: waConsent,
          consentTimestamp: waConsent ? new Date().toISOString() : null,
          captureMethod: "quiz",
          quizAnswers: answers,
          recommendation: result.product,
          fingerprintId: visitor.fingerprintId,
          isReturning: visitor.isReturning,
          intent: visitor.intent,
          source: visitor.source,
        });

        // Show success
        btn.textContent = "✓ Sent on WhatsApp!";
        btn.style.background = "#16a34a";
        phoneInput.parentElement.style.display = "none";

        log("📱 Quiz phone captured:", "+91" + phone, "| Recommendation:", result.product, "| Answers:", answers.join(", "));

        setTimeout(function () {
          overlay.style.animation = "cooee-fadeOut 0.3s ease";
          setTimeout(function () { overlay.remove(); }, 300);
        }, 2000);
      };
    }

    overlay.appendChild(popup);
    overlay.onclick = function (e) {
      if (e.target === overlay) {
        overlay.style.animation = "cooee-fadeOut 0.3s ease";
        setTimeout(function () { overlay.remove(); }, 300);
      }
    };
    document.body.appendChild(overlay);

    renderQuestion();
  }

  // ─── UI Components ───

  function createPopup(options) {
    var opts = Object.assign({
      title: "Wait! Don't leave yet!",
      subtitle: "Get 20% off on your first order",
      buttonText: "Claim Discount",
      buttonColor: "#6366f1",
      bgColor: "#ffffff",
      image: true,
      type: "popup",       // "popup", "bundle", "whatsapp", "returning"
      capture: "auto",     // "auto" = decide based on visitor, "phone", "email", "both"
      engagementId: null,
    }, options);

    if (document.getElementById("cooee-popup-overlay")) return;

    // Smart capture mode: decide what to ask for based on visitor state
    var captureMode = opts.capture;
    if (captureMode === "auto") {
      if (visitor.isReturning && !visitor.email) {
        // Returning but no email yet — they're interested, ask for phone (easier on mobile)
        captureMode = "phone";
        if (!opts.title || opts.title === "Wait! Don't leave yet!") {
          opts.title = "Welcome back! 🎉";
          opts.subtitle = "We saved a special 15% discount for you. Enter your WhatsApp to claim it.";
          opts.buttonText = "Send My Discount on WhatsApp";
        }
      } else if (visitor.device === "mobile") {
        // Mobile = phone is easier to type than email
        captureMode = "phone";
      } else {
        captureMode = "email";
      }
    }

    log("Popup capture mode:", captureMode, "(returning:", visitor.isReturning, ", device:", visitor.device, ")");

    var overlay = document.createElement("div");
    overlay.id = "cooee-popup-overlay";
    overlay.style.cssText = "position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);z-index:99999;display:flex;align-items:center;justify-content:center;animation:cooee-fadeIn 0.3s ease";

    var popup = document.createElement("div");
    popup.style.cssText = "background:" + opts.bgColor + ";border-radius:16px;max-width:420px;width:90%;box-shadow:0 25px 50px rgba(0,0,0,0.25);overflow:hidden;animation:cooee-slideUp 0.3s ease;position:relative";

    var html = "";

    if (opts.image) {
      var gradients = {
        popup: "linear-gradient(135deg,#6366f1,#8b5cf6)",
        bundle: "linear-gradient(135deg,#22c55e,#16a34a)",
        whatsapp: "linear-gradient(135deg,#25D366,#128C7E)",
        returning: "linear-gradient(135deg,#f59e0b,#ef4444)",
      };
      var emojis = { popup: "🎉", bundle: "🌿", whatsapp: "💬", returning: "👋" };
      var gradient = gradients[opts.type] || gradients.popup;
      var emoji = emojis[opts.type] || emojis.popup;
      html += '<div style="height:140px;background:' + gradient + ';display:flex;align-items:center;justify-content:center">';
      html += '<span style="font-size:56px">' + emoji + '</span>';
      html += '</div>';
    }

    html += '<div style="padding:24px;text-align:center">';
    html += '<h2 style="font-size:20px;font-weight:700;margin:0 0 8px;color:#0f172a">' + opts.title + '</h2>';
    html += '<p style="font-size:14px;color:#64748b;margin:0 0 16px">' + opts.subtitle + '</p>';

    // Phone capture field
    if (captureMode === "phone" || captureMode === "both") {
      html += '<div style="display:flex;gap:8px;margin-bottom:' + (captureMode === "both" ? "8px" : "12px") + '">';
      html += '<div style="display:flex;align-items:center;gap:4px;padding:10px 12px;border:1px solid #e2e8f0;border-radius:8px;background:#f8fafc;flex-shrink:0">';
      html += '<span style="font-size:16px">🇮🇳</span><span style="font-size:13px;color:#64748b">+91</span>';
      html += '</div>';
      html += '<input type="tel" id="cooee-phone-input" placeholder="WhatsApp number" maxlength="10" pattern="[0-9]{10}" style="flex:1;padding:10px 16px;border:1px solid #e2e8f0;border-radius:8px;font-size:14px;box-sizing:border-box;outline:none" inputmode="numeric">';
      html += '</div>';
    }

    // Email capture field
    if (captureMode === "email" || captureMode === "both") {
      html += '<input type="email" id="cooee-email-input" placeholder="Enter your email" style="width:100%;padding:10px 16px;border:1px solid #e2e8f0;border-radius:8px;font-size:14px;margin-bottom:12px;box-sizing:border-box;outline:none">';
    }

    html += '<button id="cooee-popup-btn" style="width:100%;padding:12px;background:' + opts.buttonColor + ';color:white;border:none;border-radius:8px;font-size:14px;font-weight:600;cursor:pointer;transition:opacity 0.2s" onmouseover="this.style.opacity=\'0.9\'" onmouseout="this.style.opacity=\'1\'">' + opts.buttonText + '</button>';

    // WhatsApp badge for phone capture
    if (captureMode === "phone" || captureMode === "both") {
      html += '<label style="display:flex;align-items:start;gap:6px;margin-top:10px;cursor:pointer;text-align:left">';
      html += '<input type="checkbox" id="cooee-wa-consent" checked style="margin-top:2px;accent-color:#25D366;flex-shrink:0">';
      html += '<span style="font-size:11px;color:#64748b;line-height:1.4">I agree to receive order updates & offers on WhatsApp. You can opt out anytime.</span>';
      html += '</label>';
    }

    html += '<p style="font-size:11px;color:#94a3b8;margin-top:8px">No spam. Unsubscribe anytime.</p>';
    html += '</div>';

    popup.innerHTML = html;

    // Close button
    var closeBtn = document.createElement("button");
    closeBtn.innerHTML = "✕";
    closeBtn.style.cssText = "position:absolute;top:12px;right:12px;width:28px;height:28px;border-radius:50%;border:none;background:rgba(255,255,255,0.9);cursor:pointer;font-size:14px;display:flex;align-items:center;justify-content:center;z-index:1;box-shadow:0 2px 8px rgba(0,0,0,0.1)";
    closeBtn.onclick = function () {
      overlay.style.animation = "cooee-fadeOut 0.3s ease";
      setTimeout(function () { overlay.remove(); }, 300);
      sendEvent("engagement_dismissed", { engagementId: opts.engagementId });
    };
    popup.appendChild(closeBtn);

    overlay.appendChild(popup);
    overlay.onclick = function (e) {
      if (e.target === overlay) {
        overlay.style.animation = "cooee-fadeOut 0.3s ease";
        setTimeout(function () { overlay.remove(); }, 300);
      }
    };

    document.body.appendChild(overlay);

    // CTA click handler
    var btn = document.getElementById("cooee-popup-btn");
    var emailInput = document.getElementById("cooee-email-input");
    var phoneInput = document.getElementById("cooee-phone-input");

    if (btn) {
      btn.onclick = function () {
        var email = emailInput ? emailInput.value.trim() : "";
        var phone = phoneInput ? phoneInput.value.trim().replace(/\D/g, "") : "";

        // Validate phone: Indian mobile must start with 6-9, exactly 10 digits
        if (captureMode === "phone" || captureMode === "both") {
          if (phone.length !== 10 || !/^[6-9]/.test(phone)) {
            phoneInput.style.borderColor = "#ef4444";
            phoneInput.placeholder = "Enter valid 10 digit mobile";
            return;
          }
        }
        if (captureMode === "email" || captureMode === "both") {
          if (email && !email.includes("@")) {
            emailInput.style.borderColor = "#ef4444";
            return;
          }
        }

        // Check WhatsApp consent (TRAI DND compliance)
        var waConsentEl = document.getElementById("cooee-wa-consent");
        var waConsent = waConsentEl ? waConsentEl.checked : false;
        var consentTimestamp = waConsent ? new Date().toISOString() : null;

        // Save to visitor
        if (email && email.includes("@")) visitor.email = email;
        if (phone.length === 10) visitor.phone = "+91" + phone;

        // Send events
        sendEvent("engagement_clicked", {
          engagementId: opts.engagementId,
          email: email || null,
          phone: phone ? "+91" + phone : null,
          captureMode: captureMode,
          waConsent: waConsent,
          consentTimestamp: consentTimestamp,
        });
        sendEvent("engagement_converted", { engagementId: opts.engagementId });

        if (phone || email) {
          sendEvent("contact_captured", {
            phone: phone ? "+91" + phone : null,
            email: email || null,
            waConsent: waConsent,
            consentTimestamp: consentTimestamp,
            fingerprintId: visitor.fingerprintId,
            isReturning: visitor.isReturning,
            visitCount: visitor.visitCount,
            intent: visitor.intent,
            source: visitor.source,
          });
          log("📱 Contact captured | Phone:", phone ? "+91" + phone : "—", "| WA consent:", waConsent, "| Timestamp:", consentTimestamp);
        }

        visitor.converted = true;
        saveLocal();

        // Show success
        btn.textContent = "✓ Sent!";
        btn.style.background = "#22c55e";
        if (emailInput) emailInput.style.display = "none";
        if (phoneInput) phoneInput.parentElement.style.display = "none";

        setTimeout(function () {
          overlay.style.animation = "cooee-fadeOut 0.3s ease";
          setTimeout(function () { overlay.remove(); }, 300);
        }, 1500);

        log("📱 Contact captured! Phone:", phone ? "+91" + phone : "—", "Email:", email || "—");
      };
    }
  }

  function createAnnouncementBar(options) {
    var opts = Object.assign({
      text: "Free shipping on orders above ₹499!",
      bgColor: "#6366f1",
      textColor: "#ffffff",
      closeable: true,
      engagementId: null,
    }, options);

    if (document.getElementById("cooee-announcement")) return;

    // CLS-safe: fixed position bar that overlays WITHOUT pushing body down
    // This ensures zero Cumulative Layout Shift impact
    var bar = document.createElement("div");
    bar.id = "cooee-announcement";
    bar.style.cssText = "position:fixed;top:0;left:0;width:100%;padding:10px 40px 10px 16px;background:" + opts.bgColor + ";color:" + opts.textColor + ";text-align:center;font-size:14px;font-weight:500;z-index:99998;box-sizing:border-box;animation:cooee-slideDown 0.3s ease;font-family:-apple-system,BlinkMacSystemFont,sans-serif";
    bar.textContent = opts.text;

    if (opts.closeable) {
      var close = document.createElement("button");
      close.innerHTML = "✕";
      close.style.cssText = "position:absolute;right:12px;top:50%;transform:translateY(-50%);background:none;border:none;color:" + opts.textColor + ";cursor:pointer;font-size:16px;opacity:0.7";
      close.onclick = function () {
        bar.style.animation = "cooee-slideUp 0.2s ease";
        setTimeout(function () { bar.remove(); }, 200);
        sendEvent("engagement_dismissed", { engagementId: opts.engagementId });
      };
      bar.appendChild(close);
    }

    document.body.appendChild(bar);
    // NO body margin change = zero CLS

    sendEvent("engagement_clicked", { engagementId: opts.engagementId });
  }

  function showSocialProof(options) {
    var opts = Object.assign({
      engagementId: null,
    }, options);

    // Rotate through realistic social proof messages
    var proofs = [
      { name: "Priya", location: "Mumbai", product: "Organic Turmeric Powder", time: "2 minutes ago" },
      { name: "Rahul", location: "Delhi", product: "Raw Forest Honey", time: "5 minutes ago" },
      { name: "Sneha", location: "Bangalore", product: "A2 Desi Ghee", time: "8 minutes ago" },
      { name: "Amit", location: "Pune", product: "Cold Pressed Mustard Oil", time: "12 minutes ago" },
      { name: "Kavita", location: "Jaipur", product: "Spices Combo Pack", time: "15 minutes ago" },
      { name: "Arjun", location: "Hyderabad", product: "Panchphoran Masala", time: "20 minutes ago" },
    ];

    var idx = Math.floor(Math.random() * proofs.length);
    var proof = proofs[idx];

    var notification = document.createElement("div");
    notification.id = "cooee-social-proof";
    notification.style.cssText = "position:fixed;bottom:20px;left:20px;background:white;border-radius:12px;box-shadow:0 10px 40px rgba(0,0,0,0.15);padding:12px 16px;display:flex;align-items:center;gap:12px;z-index:99997;max-width:320px;animation:cooee-slideUp 0.4s ease;font-family:-apple-system,BlinkMacSystemFont,sans-serif;border:1px solid #f1f5f9";

    notification.innerHTML =
      '<div style="width:40px;height:40px;border-radius:8px;background:linear-gradient(135deg,#6366f1,#818cf8);display:flex;align-items:center;justify-content:center;flex-shrink:0">' +
      '<span style="color:white;font-size:18px">🛒</span>' +
      '</div>' +
      '<div>' +
      '<p style="font-size:13px;font-weight:600;margin:0;color:#0f172a">' + proof.name + ' from ' + proof.location + '</p>' +
      '<p style="font-size:12px;color:#64748b;margin:2px 0 0">purchased ' + proof.product + '</p>' +
      '<p style="font-size:11px;color:#94a3b8;margin:2px 0 0">' + proof.time + '</p>' +
      '</div>';

    document.body.appendChild(notification);

    // Auto-remove after 5s
    setTimeout(function () {
      notification.style.animation = "cooee-fadeOut 0.3s ease";
      setTimeout(function () { notification.remove(); }, 300);
    }, 5000);

    sendEvent("engagement_clicked", { engagementId: opts.engagementId });
  }

  // ─── Smart Auto-Triggers ───
  function setupAutoTriggers() {
    // 1. Page load → check for page_load engagements (announcement bar, etc.)
    setTimeout(function () {
      checkEngagements("page_load");
    }, 2000);

    // 2. Exit intent → check for exit_intent engagements
    detectExitIntent(function () {
      checkEngagements("exit_intent");
    });

    // 3. Product page detection
    if (window.location.pathname.includes("/products/") || window.location.pathname.includes("/collections/")) {
      // Social proof after 8 seconds on product pages
      setTimeout(function () {
        checkEngagements("time_delay");
      }, 8000);

      // If medium+ intent and been on page 30s+, show social proof
      setTimeout(function () {
        if (visitor.intent !== "low") {
          checkEngagements("product_page");
        }
      }, 30000);
    }

    // 4. Checkout trust signals
    if (window.location.pathname.includes("/checkout")) {
      setTimeout(function () {
        checkEngagements("checkout_page");
      }, 3000);
    }

    // 5. Periodic engagement checks (every 15s)
    state.engageTimer = setInterval(function () {
      // Only check if intent has changed to medium/high
      if (visitor.intent !== "low") {
        checkEngagements("periodic");
      }
    }, config.engageCheckInterval);
  }

  // ─── Page Navigation Tracking (SPA support) ───
  function trackNavigation() {
    // For SPAs (like Shopify with AJAX navigation)
    var lastPath = window.location.pathname;

    var checkPath = function () {
      if (window.location.pathname !== lastPath) {
        lastPath = window.location.pathname;
        visitor.currentPage = lastPath;
        visitor.pageViews++;

        if (!visitor.pages.includes(lastPath)) {
          visitor.pages.push(lastPath);
        }

        saveLocal();
        sendEvent("page_view", { page: lastPath });
        calculateIntent();

        // Reset engagement checks for new page
        state.exitIntentFired = false;
        log("Page navigation:", lastPath);
      }
    };

    // Listen for history changes
    window.addEventListener("popstate", checkPath);
    var origPush = history.pushState;
    history.pushState = function () {
      origPush.apply(history, arguments);
      setTimeout(checkPath, 100);
    };
    var origReplace = history.replaceState;
    history.replaceState = function () {
      origReplace.apply(history, arguments);
      setTimeout(checkPath, 100);
    };
  }

  // ─── Inject CSS ───
  function injectStyles() {
    var style = document.createElement("style");
    style.textContent =
      "@keyframes cooee-fadeIn { from { opacity: 0; } to { opacity: 1; } }" +
      "@keyframes cooee-fadeOut { from { opacity: 1; } to { opacity: 0; } }" +
      "@keyframes cooee-slideUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }" +
      "@keyframes cooee-slideDown { from { transform: translateY(-100%); } to { transform: translateY(0); } }";
    document.head.appendChild(style);
  }

  // ─── Public API ───
  window.Cooee = {
    version: COOEE_VERSION,

    init: async function (appId, options) {
      if (state.initialized) return;
      state.initialized = true;

      config.appId = appId;
      if (options && options.apiBase) config.apiBase = options.apiBase;
      if (options && options.debug) config.debugMode = true;

      log("SDK v" + COOEE_VERSION + " starting... Loading fingerprint...");

      injectStyles();

      // Start tracking immediately (events queue until fingerprint ready)
      trackScroll();
      trackClicks();
      trackTime();
      trackIdle();
      trackNavigation();
      detectShopifyCart();
      detectShopifyCustomer();

      // Initialize visitor with fingerprint (async — loads FingerprintJS)
      await initVisitor();

      // Now fingerprint is ready — send initial event
      sendEvent("page_view", {
        page: window.location.pathname,
        isEntry: true,
        isReturning: visitor.isReturning,
        visitCount: visitor.visitCount,
        fingerprintConfidence: visitor.confidence,
      });

      // Start syncing with server
      startSync();

      // Setup auto-triggers for engagements
      setupAutoTriggers();

      log("SDK v" + COOEE_VERSION + " ready. App:", appId, "| Visitor:", visitor.id, "| Returning:", visitor.isReturning, "| Confidence:", (visitor.confidence * 100).toFixed(0) + "%");
    },

    // Manual engagement controls
    showPopup: createPopup,
    showAnnouncementBar: createAnnouncementBar,
    showSocialProof: showSocialProof,
    onExitIntent: detectExitIntent,

    // Data access
    getVisitor: function () { return Object.assign({}, visitor); },
    getIntent: function () { return { level: visitor.intent, score: visitor.intentScore }; },
    getFingerprint: function () {
      return {
        id: visitor.fingerprintId,
        confidence: visitor.confidence,
        isReturning: visitor.isReturning,
        visitCount: visitor.visitCount,
        firstSeenAt: visitor.firstSeenAt,
      };
    },
    isReturningVisitor: function () { return visitor.isReturning; },

    // Cart integration
    setCartData: function (items, value) {
      visitor.cartItems = items;
      visitor.cartValue = value;
      calculateIntent();
      sendEvent("cart_updated", { items: items, value: value });
    },

    // Event tracking
    trackEvent: function (event, data) {
      sendEvent(event, data || {});
    },

    // Email capture
    setEmail: function (email) {
      visitor.email = email;
      sendEvent("email_captured", { email: email });
    },

    // Mark conversion
    trackConversion: function (data) {
      visitor.converted = true;
      sendEvent("conversion", data || {});
    },

    // Debug mode
    debug: function (enabled) {
      config.debugMode = enabled !== false;
      if (config.debugMode) {
        console.log("[Cooee] Debug ON. Visitor:", visitor.id);
        console.log("[Cooee] 🔑 Fingerprint:", visitor.fingerprintId, "| Confidence:", (visitor.confidence * 100).toFixed(0) + "%");
        console.log("[Cooee] 👤 Returning:", visitor.isReturning, "| Visit #" + visitor.visitCount);
        console.log("[Cooee] 🎯 Intent:", visitor.intent, "| Score:", visitor.intentScore);
        console.log("[Cooee] 🛒 Cart:", visitor.cartItems, "items, ₹" + visitor.cartValue);
        console.log("[Cooee] 📍 Source:", visitor.source, "| Device:", visitor.device);
        console.log("[Cooee] 📄 Pages:", visitor.pages.join(" → "));
      }
    },
  };

  // ─── Auto-init from script tag ───
  var scripts = document.querySelectorAll("script[data-app-id]");
  scripts.forEach(function (s) {
    var appId = s.getAttribute("data-app-id");
    var apiBase = s.getAttribute("data-api-base") || "";
    var debug = s.getAttribute("data-debug") === "true";
    if (appId) {
      window.Cooee.init(appId, { apiBase: apiBase, debug: debug });
    }
  });

})(window, document);
